import { type ClassValue, clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/** Cria um elemento HTML com atributos e filhos. */
export function el<K extends keyof HTMLElementTagNameMap>(
  tag: K,
  attrs: Record<string, string> = {},
  ...children: (string | Node)[]
): HTMLElementTagNameMap[K] {
  const element = document.createElement(tag);
  for (const [key, value] of Object.entries(attrs)) {
    element.setAttribute(key, value);
  }
  for (const child of children) {
    if (typeof child === 'string') {
      element.appendChild(document.createTextNode(child));
    } else {
      element.appendChild(child);
    }
  }
  return element;
}

/** Renderiza HTML string num container (com sanitização externa). */
export function renderHtml(container: Element, html: string): void {
  container.innerHTML = html;
}

/**
 * Sanitizador mínimo de HTML para uso em innerHTML.
 *
 * Tags permitidas: <strong>, <em>, <b>, <i>, <code>, <a>, <br>, <span>
 * Removidos: <script>, <style>, <iframe>, <object>, <embed>, handlers on*, javascript:
 */

const DANGEROUS_BLOCKS_RE =
  /<(script|style|iframe|object|embed|form)[^>]*>[\s\S]*?<\/\1>/gi;
const DANGEROUS_VOID_RE =
  /<(?:script|style|iframe|object|embed|form|input|link|meta)[^>]*\/?>/gi;
const EVENT_HANDLERS_RE = /\s+on\w+\s*=\s*(?:"[^"]*"|'[^']*'|\S+)/gi;
const JAVASCRIPT_PROTOCOL_RE =
  /(href|src|action)\s*=\s*["']?\s*javascript:/gi;

export function sanitizeHtml(html: string): string {
  return html
    .replace(DANGEROUS_BLOCKS_RE, '')
    .replace(DANGEROUS_VOID_RE, '')
    .replace(EVENT_HANDLERS_RE, '')
    .replace(JAVASCRIPT_PROTOCOL_RE, '$1="about:blank"');
}

/*
 * ─── Design Tokens — Source of Truth ─────────────────────────────────────────
 * Gerado a partir de docs/shared/tokens/tokens.json
 * Todos os projetos importam este arquivo via @import "@shared/tokens/tokens.css"
 * NÃO edite diretamente — edite tokens.json e regenere.
 */

/* ── Google Fonts ─────────────────────────────────────────────────────────── */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Lexend:wght@400;500;600;700;800&family=PT+Serif:wght@400;700&family=LXGW+WenKai+TC:wght@400;700&display=swap');

/* ── Light mode (default) ─────────────────────────────────────────────────── */
:root {
  --font-size: 16px;

  /* Typography — font sizes */
  --text-h1: 48px;
  --text-h2: 30px;
  --text-h3: 20px;
  --text-h4: 16px;
  --text-p: 14px;
  --text-label: 12px;

  /* Typography — font family
     --font-family-active é trocado pelas classes .fonte-* no <html>.
     --font-family aponta sempre para o active para que consumidores existentes
     (componentes que usam var(--font-family)) acompanhem a troca. */
  --font-family-active: 'Inter', sans-serif;
  --font-family: var(--font-family-active);

  /* Typography — font weights */
  --font-weight-extra-bold: 800;
  --font-weight-semi-bold: 600;
  --font-weight-medium: 500;
  --font-weight-regular: 400;

  /* Typography — line heights */
  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;
  --line-height-loose: 2;

  /* Typography — letter spacing */
  --letter-spacing-tight: -0.02em;
  --letter-spacing-normal: 0em;
  --letter-spacing-wide: 0.02em;

  /* Surfaces */
  --background: 0 0% 100%;
  --foreground: 0 0% 4%;
  --card: 0 0% 100%;
  --card-foreground: 0 0% 4%;
  --popover: 0 0% 100%;
  --popover-foreground: 0 0% 4%;

  /* Brand / Interactive */
  --primary: 0 0% 9%;
  --primary-foreground: 0 0% 98%;
  --secondary: 0 0% 96%;
  --secondary-foreground: 0 0% 4%;
  --muted: 0 0% 96%;
  --muted-foreground: 0 0% 40%;
  --accent: 0 0% 96%;
  --accent-foreground: 0 0% 9%;

  /* Feedback — cores com contraste WCAG 2.1 AA (≥4.5:1) para texto sobre bg colorido
     E também para text-<color> sobre bg-<color>/10 (soft variants do shadcn radix-nova) */
  --destructive: 0 74% 42%;
  --destructive-foreground: 0 0% 100%;
  --success: 142 85% 22%;
  --success-foreground: 0 0% 100%;
  --warning: 45 95% 36%;
  --warning-foreground: 0 0% 100%;
  --info: 221 83% 43%;
  --info-foreground: 0 0% 100%;

  /* Structure */
  --border: 0 0% 90%;
  --input: 0 0% 90%;
  --input-background: 0 0% 100%;
  --ring: 0 0% 45%;
  --ring-offset-width: 2px;
  --ring-offset-color: 0 0% 100%;

  /* Spacing base — consumido pelo Tailwind v4 via @theme inline (--spacing).
     Tailwind calcula p-{n}, gap-{n}, m-{n}, space-{n}, etc. como n × --spacing-base.
     Densidades em themes/densities.css override este valor (condensado/confortável),
     afetando TODOS os espaçamentos proporcionalmente. */
  --spacing-base: 0.25rem; /* 4px — padrão Tailwind */

  /* Spacing scale — grid de 8 (múltiplos ou divisores de 8 apenas).
     Use estes tokens em CSS standalone (.mbds-*, basecoat-overrides) quando
     precisar de um valor de spacing nomeado.
     Acompanham a densidade automaticamente porque referenciam --spacing-base.

     Regra do projeto: spacing deve ser múltiplo OU divisor de 8.
     Valores fora do grid (10, 12, 14, 20, 28, 36, 44, 56...) NÃO devem existir
     como tokens — se aparecerem em CSS, são bug a ser corrigido. */
  --spacing-0:   0;
  --spacing-px:  1px;                               /* hairline / border */
  --spacing-0-5: calc(var(--spacing-base) * 0.5);   /* 2px  — divisor de 8 (8÷4) */
  --spacing-1:   calc(var(--spacing-base) * 1);     /* 4px  — divisor de 8 (8÷2) */
  --spacing-2:   calc(var(--spacing-base) * 2);     /* 8px  — base do grid */
  --spacing-4:   calc(var(--spacing-base) * 4);     /* 16px */
  --spacing-6:   calc(var(--spacing-base) * 6);     /* 24px */
  --spacing-8:   calc(var(--spacing-base) * 8);     /* 32px */
  --spacing-10:  calc(var(--spacing-base) * 10);    /* 40px */
  --spacing-12:  calc(var(--spacing-base) * 12);    /* 48px */
  --spacing-14:  calc(var(--spacing-base) * 14);    /* 56px */
  --spacing-16:  calc(var(--spacing-base) * 16);    /* 64px */
  --spacing-20:  calc(var(--spacing-base) * 20);    /* 80px */
  --spacing-24:  calc(var(--spacing-base) * 24);    /* 96px */

  /* Elevation / Shadows */
  --elevation-sm: 0px 1px 2px 0px rgba(0, 0, 0, 0.1);
  --elevation-md: 0px 4px 6px -1px rgba(0, 0, 0, 0.1), 0px 2px 4px -1px rgba(0, 0, 0, 0.06);
  --elevation-lg: 0px 10px 15px -3px rgba(0, 0, 0, 0.1), 0px 4px 6px -2px rgba(0, 0, 0, 0.05);
  --elevation-xl: 0px 20px 25px -5px rgba(0, 0, 0, 0.1), 0px 10px 10px -5px rgba(0, 0, 0, 0.04);

  /* Charts */
  --chart-1: 199 89% 65%;
  --chart-2: 200 100% 50%;
  --chart-3: 201 98% 48%;
  --chart-4: 201 88% 43%;
  --chart-5: 210 71% 23%;

  /* Radius — arquitetura fiel ao shadcn (base-nova/reka-nova/etc.):
     --radius é o tamanho base global. Cada componente consome um token
     específico (--radius-button, --radius-card, etc.) que no tema padrão
     (Default) é igual ao --radius, mas em outros temas pode aplicar
     multiplicadores diferentes (ver docs/shared/themes/<tema>.css).

     Valor base = 0.625rem (10px) bate exatamente com shadcn default. */
  --radius: 0.625rem;              /* 10px — base global */
  --radius-button: var(--radius);  /* Default: 1× */
  --radius-card: calc(var(--radius) * 1.4);   /* Default: 14px */
  --radius-badge: calc(var(--radius) * 2.6);  /* Default: 26px */
  --radius-input: var(--radius);   /* Default: 1× */
  --radius-alert: var(--radius);   /* Default: 1× */

  /* Dimension tokens — altura default de interativos (Button, Input, Select, Toggle, Badge...) */
  /* Nota: Tailwind v4 consome via h-(--height-*) / size-(--size-*) / px-(--spacing-*) */
  --height-badge: 1.25rem;    /* 20px — h-5 (compacto, só para Badge) */
  --height-xs: 1.5rem;        /* 24px — h-6 default */
  --height-sm: 1.75rem;       /* 28px — h-7 */
  --height-default: 2rem;     /* 32px — h-8 */
  --height-lg: 2.25rem;       /* 36px — h-9 */
  --height-xl: 2.5rem;        /* 40px — h-10 */

  --size-xs: 1.5rem;          /* 24px — size-6 */
  --size-sm: 1.75rem;         /* 28px — size-7 */
  --size-default: 2rem;       /* 32px — size-8 */
  --size-lg: 2.25rem;         /* 36px — size-9 */
  --size-xl: 2.5rem;          /* 40px — size-10 */

  --spacing-btn-x: 0.625rem;  /* 10px — px-2.5 default */
  --spacing-btn-x-sm: 0.625rem;
  --spacing-btn-x-lg: 0.625rem;

  /* Stroke (para variantes com borda visível) */
  --border-width-default: 1px;

  /* Transitions */
  --transition-fast: 150ms;
  --transition-normal: 300ms;
  --transition-slow: 500ms;
  --transition-timing: cubic-bezier(0.4, 0, 0.2, 1);

  /* Z-index */
  --z-dropdown: 1000;
  --z-sticky: 1020;
  --z-fixed: 1030;
  --z-modal-backdrop: 1040;
  --z-modal: 1050;
  --z-popover: 1060;
  --z-tooltip: 1070;

  /* Sidebar */
  --sidebar: 0 0% 98%;
  --sidebar-foreground: 0 0% 4%;
  --sidebar-primary: 0 0% 9%;
  --sidebar-primary-foreground: 0 0% 98%;
  --sidebar-accent: 0 0% 96%;
  --sidebar-accent-foreground: 0 0% 9%;
  --sidebar-border: 0 0% 83%;
  --sidebar-ring: 0 0% 45%;
}

/* ── Dark mode ────────────────────────────────────────────────────────────── */
.dark {
  --background: 0 0% 9%;
  --foreground: 0 0% 98%;
  --card: 0 0% 9%;
  --card-foreground: 0 0% 98%;
  --popover: 0 0% 9%;
  --popover-foreground: 0 0% 98%;
  --primary: 0 0% 98%;
  --primary-foreground: 0 0% 9%;
  --secondary: 0 0% 15%;
  --secondary-foreground: 0 0% 98%;
  --muted: 0 0% 15%;
  --muted-foreground: 0 0% 70%;
  --accent: 0 0% 15%;
  --accent-foreground: 0 0% 98%;
  --destructive: 0 85% 70%;
  --destructive-foreground: 0 0% 100%;
  --success: 142 71% 55%;
  --success-foreground: 0 0% 0%;
  --warning: 48 95% 60%;
  --warning-foreground: 0 0% 0%;
  --info: 221 83% 53%;
  --info-foreground: 0 0% 100%;
  --border: 0 0% 15%;
  --input: 0 0% 15%;
  --input-background: 0 0% 9%;
  --ring: 0 0% 45%;
  --ring-offset-color: 0 0% 9%;
  --elevation-sm: 0px 1px 2px 0px rgba(0, 0, 0, 0.3);
  --elevation-md: 0px 4px 6px -1px rgba(0, 0, 0, 0.3), 0px 2px 4px -1px rgba(0, 0, 0, 0.2);
  --elevation-lg: 0px 10px 15px -3px rgba(0, 0, 0, 0.3), 0px 4px 6px -2px rgba(0, 0, 0, 0.2);
  --elevation-xl: 0px 20px 25px -5px rgba(0, 0, 0, 0.3), 0px 10px 10px -5px rgba(0, 0, 0, 0.1);
  --sidebar: 0 0% 9%;
  --sidebar-foreground: 0 0% 98%;
  --sidebar-primary: 0 0% 98%;
  --sidebar-primary-foreground: 0 0% 9%;
  --sidebar-accent: 0 0% 15%;
  --sidebar-accent-foreground: 0 0% 98%;
  --sidebar-border: 0 0% 15%;
  --sidebar-ring: 0 0% 45%;
}

/*
 * ─── Temas de Marca ───────────────────────────────────────────────────────────
 * Default é o tema padrão (sem classe). Warm e Cold são variantes de cor.
 *
 * Todos os projetos importam via: @import "@shared/themes/index.css"
 */
@import "./default.css";
@import "./warm.css";
@import "./cold.css";
@import "./densities.css";
@import "./fonts.css";

/*
 * ─── Tema: Default ────────────────────────────────────────────────────────────
 * Referência shadcn: style base. Vibe: moderno, compacto, cantos suaves, densidade média-alta.
 *
 * Radius: base 10px; componentes seguem multiplicadores shadcn:
 *   button: 1×, card: 1.4×, badge: 2.6×, input: 1×, alert: 1×
 *
 * Os valores em :root (tokens.css) refletem Default. Este arquivo RE-DECLARA
 * os mesmos tokens dentro de `.tema-default` para garantir que, ao voltar de
 * `.tema-warm` ou `.tema-cold` no preview do Storybook, o cascade do CSS reverta
 * corretamente (sem essa re-declaração, browsers podem manter estado computado
 * mesmo após a remoção da classe override).
 *
 * Base Color: Neutral · Theme Color: Neutral · Chart Color: Neutral
 */
.tema-default {
  --background: 0 0% 100%;
  --foreground: 0 0% 4%;
  --card: 0 0% 100%;
  --card-foreground: 0 0% 4%;
  --popover: 0 0% 100%;
  --popover-foreground: 0 0% 4%;

  --primary: 0 0% 9%;
  --primary-foreground: 0 0% 98%;
  --secondary: 0 0% 96%;
  --secondary-foreground: 0 0% 4%;
  --muted: 0 0% 96%;
  --muted-foreground: 0 0% 40%;
  --accent: 0 0% 96%;
  --accent-foreground: 0 0% 9%;

  --destructive: 0 74% 42%;
  --destructive-foreground: 0 0% 100%;
  --success: 142 85% 22%;
  --success-foreground: 0 0% 100%;
  --warning: 45 95% 36%;
  --warning-foreground: 0 0% 100%;
  --info: 221 83% 43%;
  --info-foreground: 0 0% 100%;

  --border: 0 0% 90%;
  --input: 0 0% 90%;
  --input-background: 0 0% 100%;
  --ring: 0 0% 45%;
  --ring-offset-color: 0 0% 100%;
}

/* Dark mode — combina `.dark.tema-default` */
.dark.tema-default {
  --background: 0 0% 4%;
  --foreground: 0 0% 98%;
  --card: 0 0% 6%;
  --card-foreground: 0 0% 98%;
  --popover: 0 0% 6%;
  --popover-foreground: 0 0% 98%;

  --primary: 0 0% 98%;
  --primary-foreground: 0 0% 9%;
  --secondary: 0 0% 15%;
  --secondary-foreground: 0 0% 98%;
  --muted: 0 0% 15%;
  --muted-foreground: 0 0% 65%;
  --accent: 0 0% 15%;
  --accent-foreground: 0 0% 98%;

  --destructive: 0 85% 70%;
  --destructive-foreground: 0 0% 100%;
  --success: 142 71% 55%;
  --success-foreground: 0 0% 0%;
  --warning: 48 95% 60%;
  --warning-foreground: 0 0% 0%;
  --info: 221 83% 53%;
  --info-foreground: 0 0% 100%;

  --border: 0 0% 15%;
  --input: 0 0% 20%;
  --input-background: 0 0% 8%;
  --ring: 0 0% 70%;
  --ring-offset-color: 0 0% 4%;
}

/*
 * ─── Tema: Warm ───────────────────────────────────────────────────────────────
 * Variante de cores quentes do tema Default.
 *
 * Estratégia:
 *   - Neutros (background, foreground, primary, secondary, muted, accent, border)
 *     ganham tint âmbar/marrom sutil (matiz ~30°, saturação 8–15%) — continuam
 *     "quase cinzas", mas a tela tem temperatura quente.
 *   - Feedback colors (destructive/success/warning/info) deslocam suavemente
 *     para o lado quente do espectro mantendo contraste WCAG AA.
 *   - Charts trocam paleta azul por paleta âmbar/laranja.
 *   - Radius, dimensões e shadows herdam de tokens.css (Default).
 *
 * Aplicado via classe `.tema-warm` no <html>. Dark mode combina com `.dark`.
 */

.tema-warm {
  /* Surfaces — tint âmbar muito sutil */
  --background: 30 25% 99%;
  --foreground: 25 20% 8%;
  --card: 30 25% 99%;
  --card-foreground: 25 20% 8%;
  --popover: 30 25% 99%;
  --popover-foreground: 25 20% 8%;

  /* Brand / Interactive — primary terracota saturado; secondary/accent creme âmbar */
  --primary: 18 75% 35%;            /* terracota / laranja queimado */
  --primary-foreground: 30 30% 98%;
  --secondary: 35 55% 92%;          /* creme âmbar claro */
  --secondary-foreground: 18 60% 22%;
  --muted: 30 20% 95%;
  --muted-foreground: 25 12% 42%;
  --accent: 35 55% 92%;             /* espelha secondary */
  --accent-foreground: 18 60% 22%;

  /* Feedback — paleta quente */
  --destructive: 0 74% 42%;
  --destructive-foreground: 0 0% 100%;
  --success: 130 60% 28%;
  --success-foreground: 0 0% 100%;
  --warning: 28 95% 38%;
  --warning-foreground: 0 0% 100%;
  --info: 24 85% 45%;
  --info-foreground: 0 0% 100%;

  /* Structure */
  --border: 30 15% 88%;
  --input: 30 15% 88%;
  --input-background: 30 25% 99%;
  --ring: 18 75% 45%;               /* alinhado com primary */
  --ring-offset-color: 30 25% 99%;

  /* Charts — paleta âmbar/laranja */
  --chart-1: 32 95% 60%;
  --chart-2: 24 90% 50%;
  --chart-3: 18 85% 45%;
  --chart-4: 36 75% 55%;
  --chart-5: 14 70% 40%;

  /* Sidebar — tint quente */
  --sidebar: 30 25% 98%;
  --sidebar-foreground: 25 20% 8%;
  --sidebar-primary: 18 75% 35%;
  --sidebar-primary-foreground: 30 30% 98%;
  --sidebar-accent: 35 55% 92%;
  --sidebar-accent-foreground: 18 60% 22%;
  --sidebar-border: 30 15% 85%;
  --sidebar-ring: 18 75% 45%;
}

/* Dark mode — combina `.dark.tema-warm` */
.dark.tema-warm {
  --background: 25 15% 9%;
  --foreground: 30 20% 96%;
  --card: 25 15% 9%;
  --card-foreground: 30 20% 96%;
  --popover: 25 15% 9%;
  --popover-foreground: 30 20% 96%;
  --primary: 22 85% 60%;            /* laranja vibrante no dark */
  --primary-foreground: 25 30% 10%;
  --secondary: 25 20% 18%;          /* marrom escuro saturado */
  --secondary-foreground: 35 55% 90%;
  --muted: 25 10% 16%;
  --muted-foreground: 30 12% 70%;
  --accent: 25 20% 18%;
  --accent-foreground: 35 55% 90%;
  --destructive: 0 80% 65%;
  --destructive-foreground: 0 0% 100%;
  --success: 130 60% 55%;
  --success-foreground: 0 0% 0%;
  --warning: 35 92% 55%;
  --warning-foreground: 0 0% 0%;
  --info: 24 85% 58%;
  --info-foreground: 0 0% 100%;
  --border: 25 10% 16%;
  --input: 25 10% 16%;
  --input-background: 25 15% 9%;
  --ring: 22 85% 55%;
  --ring-offset-color: 25 15% 9%;
  --sidebar: 25 15% 9%;
  --sidebar-foreground: 30 20% 96%;
  --sidebar-primary: 22 85% 60%;
  --sidebar-primary-foreground: 25 30% 10%;
  --sidebar-accent: 25 20% 18%;
  --sidebar-accent-foreground: 35 55% 90%;
  --sidebar-border: 25 10% 16%;
  --sidebar-ring: 22 85% 55%;
}

/*
 * ─── Tema: Cold ───────────────────────────────────────────────────────────────
 * Variante de cores frias do tema Default.
 *
 * Estratégia:
 *   - Neutros (background, foreground, primary, secondary, muted, accent, border)
 *     ganham tint azul/cyan sutil (matiz ~210°, saturação 8–15%) — continuam
 *     "quase cinzas", mas a tela tem temperatura fria.
 *   - Feedback colors (destructive/success/warning/info) deslocam suavemente
 *     para o lado frio do espectro mantendo contraste WCAG AA.
 *   - Charts trocam paleta padrão por azul/cyan/teal.
 *   - Radius, dimensões e shadows herdam de tokens.css (Default).
 *
 * Aplicado via classe `.tema-cold` no <html>. Dark mode combina com `.dark`.
 */

.tema-cold {
  /* Surfaces — tint azul muito sutil */
  --background: 210 30% 99%;
  --foreground: 215 25% 8%;
  --card: 210 30% 99%;
  --card-foreground: 215 25% 8%;
  --popover: 210 30% 99%;
  --popover-foreground: 215 25% 8%;

  /* Brand / Interactive — primary azul royal saturado; secondary/accent azul-gelo */
  --primary: 215 80% 38%;           /* azul royal */
  --primary-foreground: 210 30% 98%;
  --secondary: 205 55% 92%;         /* azul-gelo claro */
  --secondary-foreground: 215 70% 25%;
  --muted: 210 20% 95%;
  --muted-foreground: 215 12% 42%;
  --accent: 205 55% 92%;            /* espelha secondary */
  --accent-foreground: 215 70% 25%;

  /* Feedback — paleta fria */
  --destructive: 350 75% 42%;
  --destructive-foreground: 0 0% 100%;
  --success: 165 75% 26%;
  --success-foreground: 0 0% 100%;
  --warning: 200 95% 35%;
  --warning-foreground: 0 0% 100%;
  --info: 215 85% 45%;
  --info-foreground: 0 0% 100%;

  /* Structure */
  --border: 210 18% 88%;
  --input: 210 18% 88%;
  --input-background: 210 30% 99%;
  --ring: 215 80% 48%;              /* alinhado com primary */
  --ring-offset-color: 210 30% 99%;

  /* Charts — paleta azul/cyan/teal */
  --chart-1: 210 90% 60%;
  --chart-2: 195 85% 50%;
  --chart-3: 180 75% 40%;
  --chart-4: 225 80% 55%;
  --chart-5: 240 70% 45%;

  /* Sidebar — tint frio */
  --sidebar: 210 30% 98%;
  --sidebar-foreground: 215 25% 8%;
  --sidebar-primary: 215 80% 38%;
  --sidebar-primary-foreground: 210 30% 98%;
  --sidebar-accent: 205 55% 92%;
  --sidebar-accent-foreground: 215 70% 25%;
  --sidebar-border: 210 18% 85%;
  --sidebar-ring: 215 80% 48%;
}

/* Dark mode — combina `.dark.tema-cold` */
.dark.tema-cold {
  --background: 215 25% 9%;
  --foreground: 210 25% 96%;
  --card: 215 25% 9%;
  --card-foreground: 210 25% 96%;
  --popover: 215 25% 9%;
  --popover-foreground: 210 25% 96%;
  --primary: 210 90% 62%;           /* azul vibrante no dark */
  --primary-foreground: 215 30% 10%;
  --secondary: 215 25% 18%;         /* azul-marinho escuro */
  --secondary-foreground: 205 55% 90%;
  --muted: 215 15% 16%;
  --muted-foreground: 210 12% 70%;
  --accent: 215 25% 18%;
  --accent-foreground: 205 55% 90%;
  --destructive: 350 80% 65%;
  --destructive-foreground: 0 0% 100%;
  --success: 165 70% 50%;
  --success-foreground: 0 0% 0%;
  --warning: 200 92% 55%;
  --warning-foreground: 0 0% 0%;
  --info: 215 85% 60%;
  --info-foreground: 0 0% 100%;
  --border: 215 15% 16%;
  --input: 215 15% 16%;
  --input-background: 215 25% 9%;
  --ring: 210 90% 58%;
  --ring-offset-color: 215 25% 9%;
  --sidebar: 215 25% 9%;
  --sidebar-foreground: 210 25% 96%;
  --sidebar-primary: 210 90% 62%;
  --sidebar-primary-foreground: 215 30% 10%;
  --sidebar-accent: 215 25% 18%;
  --sidebar-accent-foreground: 205 55% 90%;
  --sidebar-border: 215 15% 16%;
  --sidebar-ring: 210 90% 58%;
}

/*
 * ─── Densidades ───────────────────────────────────────────────────────────────
 * Ajusta o tamanho base de spacing do projeto, afetando proporcionalmente
 * TODAS as classes Tailwind p-*, m-*, gap-*, space-* (via @theme --spacing).
 *
 * Também ajusta as alturas tokenizadas (--height-*, --size-*) para que
 * botões/inputs/selects acompanhem a densidade.
 *
 * Aplicado via classe no <html>:
 *   default (sem classe)          — --spacing-base = 4px
 *   .densidade-condensado          — --spacing-base ≈ 3.2px (~80%)
 *   .densidade-confortavel         — --spacing-base ≈ 5px   (~125%)
 *
 * Pode combinar com qualquer tema de cor (.tema-warm, .tema-cold) e com .dark.
 */

/* ── Default — re-declara os valores de :root para garantir cascade
 *    correto ao voltar de condensado/confortável. Mesmos números de tokens.css. */
.densidade-default {
  --spacing-base: 0.25rem;         /* 4px */

  --height-badge: 1.25rem;         /* 20px */
  --height-xs: 1.5rem;             /* 24px */
  --height-sm: 1.75rem;            /* 28px */
  --height-default: 2rem;          /* 32px */
  --height-lg: 2.25rem;            /* 36px */
  --height-xl: 2.5rem;             /* 40px */

  --size-xs: 1.5rem;
  --size-sm: 1.75rem;
  --size-default: 2rem;
  --size-lg: 2.25rem;
  --size-xl: 2.5rem;
}

/* ── Condensado — interfaces densas, mais informação na tela ──────────────── */
.densidade-condensado {
  --spacing-base: 0.20rem;        /* 3.2px (80% do padrão) */

  /* Heights/sizes escalonados proporcionalmente */
  --height-badge: 1rem;            /* 16px */
  --height-xs: 1.25rem;            /* 20px */
  --height-sm: 1.5rem;             /* 24px */
  --height-default: 1.75rem;       /* 28px */
  --height-lg: 2rem;               /* 32px */
  --height-xl: 2.25rem;            /* 36px */

  --size-xs: 1.25rem;
  --size-sm: 1.5rem;
  --size-default: 1.75rem;
  --size-lg: 2rem;
  --size-xl: 2.25rem;
}

/* ── Confortável — interfaces folgadas, mais respiro ──────────────────────── */
.densidade-confortavel {
  --spacing-base: 0.3125rem;      /* 5px (125% do padrão) */

  /* Heights/sizes escalonados proporcionalmente */
  --height-badge: 1.5rem;          /* 24px */
  --height-xs: 1.75rem;            /* 28px */
  --height-sm: 2rem;               /* 32px */
  --height-default: 2.5rem;        /* 40px */
  --height-lg: 2.75rem;            /* 44px */
  --height-xl: 3rem;               /* 48px */

  --size-xs: 1.75rem;
  --size-sm: 2rem;
  --size-default: 2.5rem;
  --size-lg: 2.75rem;
  --size-xl: 3rem;
}

/*
 * ─── Fontes ───────────────────────────────────────────────────────────────────
 * Sobrescreve --font-family-active, que é consumido por --font-family.
 * Os @import das fontes ficam em tokens.css (carregados uma vez).
 *
 * Aplicado via classe no <html>:
 *   default (sem classe)  — Inter (padrão)
 *   .fonte-lexend          — Lexend (humanista, ampla, alta legibilidade)
 *   .fonte-pt-serif        — PT Serif (serifada clássica)
 *   .fonte-lxgw-wenkai     — LXGW WenKai TC (manuscrita tradicional chinesa/latina)
 *
 * Combina com qualquer tema de cor, densidade e light/dark.
 */

/* Default — re-declara para garantir cascade ao voltar de outra fonte */
.fonte-default {
  --font-family-active: 'Inter', sans-serif;
}

.fonte-lexend {
  --font-family-active: 'Lexend', sans-serif;
}

.fonte-pt-serif {
  --font-family-active: 'PT Serif', Georgia, serif;
}

.fonte-lxgw-wenkai {
  --font-family-active: 'LXGW WenKai TC', 'Kaiti', cursive;
}
